Hi @darshankawar ,
I tried to reproduce the issue with `webview_flutter` by setting `displayWithHybridComposition` to true. (Please correct me if I used it incorrectly.)"

Here is the sample code:
<details>
    <summary>Sample code</summary>

```dart
import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';
import 'package:webview_flutter_android/webview_flutter_android.dart';
import 'package:webview_flutter_platform_interface/webview_flutter_platform_interface.dart';

void main() => runApp(const MaterialApp(home: HomePage()));

class HomePage extends StatefulWidget {
  const HomePage({super.key});

  @override
  State<HomePage> createState() => _HomePageState();
}

class _HomePageState extends State<HomePage> {
  @override
  Widget build(BuildContext context) => Scaffold(
        body: Center(
          child: ElevatedButton(
            child: const Text("Show WebView in BottomSheet"),
            onPressed: () {
              showModalBottomSheet<void>(
                context: context,
                isScrollControlled: true,
                builder: (context) => const SizedBox(height: 600, child: InAppWebViewPage()),
              );
            },
          ),
        ),
      );
}

class InAppWebViewPage extends StatefulWidget {
  const InAppWebViewPage({super.key});

  @override
  State<InAppWebViewPage> createState() => _InAppWebViewPageState();
}

class _InAppWebViewPageState extends State<InAppWebViewPage> {
  @override
  Widget build(BuildContext context) {
    final controller = AndroidWebViewController(AndroidWebViewControllerCreationParams());
    final params = AndroidWebViewWidgetCreationParams(
      controller: controller,
      displayWithHybridComposition: true,
    );
    controller.loadRequest(LoadRequestParams(uri: Uri.parse('https://buy.line.me/')));

    return Scaffold(
      appBar: AppBar(title: const Text('WebView Flutter')),
      body: WebViewWidget.fromPlatformCreationParams(params: params),
    );
  }
}
```

</details>

The plugins I imported:
```
webview_flutter_android: ^3.16.1
webview_flutter: ^4.7.0
```

The same bug happens as previously mentioned.
Please take a look if you have time. Thank you.

By the way, I also left a comment on the [InAppWebView Plugin Github](https://github.com/pichillilorenzo/flutter_inappwebview/issues/1675#issuecomment-2103998535)

